// Fuzzy Matching Engine - Implements the scoring algorithm from the spec
//
// Matching strategy: Acronym + Substring matching
// - Matches contiguous substrings: "stage" matches "Stage All"
// - Matches first letters of words: "sa" matches "Stage All"
// - Matches camelCase/snake_case boundaries: "sf" matches "StageFile"
// - Case-insensitive by default

#include "../include/app.h"
#include <cwchar>
#include <cctype>
#include <cstring>

// ============================================================================
// Character Classification Helpers
// ============================================================================

static inline bool is_word_boundary(wchar_t prev, wchar_t curr) {
    // Start of string is a word boundary
    if (prev == 0) return true;

    // Space/underscore/hyphen followed by any char
    if (prev == L' ' || prev == L'_' || prev == L'-' || prev == L'/') return true;

    // Lowercase followed by uppercase (camelCase)
    if (iswlower(prev) && iswupper(curr)) return true;

    return false;
}

static inline wchar_t to_lower(wchar_t c) {
    return (wchar_t)towlower(c);
}

static inline bool chars_equal_ci(wchar_t a, wchar_t b) {
    return to_lower(a) == to_lower(b);
}

// ============================================================================
// Match Type Detection
// ============================================================================

// Check if query is an exact prefix of target (case-insensitive)
static bool is_exact_prefix(const wchar_t* query, size_t query_len,
                            const wchar_t* target, size_t target_len) {
    if (query_len > target_len) return false;

    for (size_t i = 0; i < query_len; i++) {
        if (!chars_equal_ci(query[i], target[i])) return false;
    }
    return true;
}

// Check if query matches word boundaries in target
// e.g., "sa" matches "Stage All" (S from Stage, A from All)
static bool is_word_boundary_match(const wchar_t* query, size_t query_len,
                                   const wchar_t* target, size_t target_len,
                                   uint64_t* out_mask) {
    size_t q = 0;  // Query position
    wchar_t prev = 0;
    *out_mask = 0;

    for (size_t t = 0; t < target_len && q < query_len && t < 64; t++) {
        wchar_t curr = target[t];

        // Only match at word boundaries
        if (is_word_boundary(prev, curr)) {
            if (chars_equal_ci(query[q], curr)) {
                *out_mask |= (1ULL << t);
                q++;
            }
        }
        prev = curr;
    }

    return q == query_len;
}

// Check if query appears as a substring anywhere in target
static bool is_substring_match(const wchar_t* query, size_t query_len,
                               const wchar_t* target, size_t target_len,
                               uint64_t* out_mask) {
    if (query_len > target_len) return false;

    for (size_t start = 0; start <= target_len - query_len; start++) {
        bool match = true;
        for (size_t i = 0; i < query_len; i++) {
            if (!chars_equal_ci(query[i], target[start + i])) {
                match = false;
                break;
            }
        }

        if (match) {
            *out_mask = 0;
            for (size_t i = 0; i < query_len && (start + i) < 64; i++) {
                *out_mask |= (1ULL << (start + i));
            }
            return true;
        }
    }

    return false;
}

// Check if all query characters appear in target in order (fuzzy match)
static bool is_fuzzy_subsequence(const wchar_t* query, size_t query_len,
                                 const wchar_t* target, size_t target_len,
                                 uint64_t* out_mask, size_t* matched_chars) {
    size_t q = 0;
    *out_mask = 0;
    *matched_chars = 0;

    for (size_t t = 0; t < target_len && q < query_len; t++) {
        if (chars_equal_ci(query[q], target[t])) {
            if (t < 64) {
                *out_mask |= (1ULL << t);
            }
            (*matched_chars)++;
            q++;
        }
    }

    return q == query_len;
}

// ============================================================================
// Main Fuzzy Match Function
// ============================================================================

FuzzyMatchResult fuzzy_match(const wchar_t* query, const wchar_t* target) {
    FuzzyMatchResult result = { 0, 0, false };

    if (!query || !target) return result;

    size_t query_len = wcslen(query);
    size_t target_len = wcslen(target);

    // Empty query matches everything with score 0
    if (query_len == 0) {
        result.matched = true;
        return result;
    }

    if (target_len == 0) return result;

    int score = 0;
    uint64_t mask = 0;
    size_t matched_chars = 0;

    // Score based on match type (from spec)
    // Priority: Exact prefix > Word boundary > Substring > Fuzzy

    if (is_exact_prefix(query, query_len, target, target_len)) {
        // Exact prefix match: +100
        score = 100;
        for (size_t i = 0; i < query_len && i < 64; i++) {
            mask |= (1ULL << i);
        }
        matched_chars = query_len;
    }
    else if (is_word_boundary_match(query, query_len, target, target_len, &mask)) {
        // Word boundary match (includes acronym matching): +60
        score = 60;
        matched_chars = query_len;
    }
    else if (is_substring_match(query, query_len, target, target_len, &mask)) {
        // Substring anywhere: +20
        score = 20;
        matched_chars = query_len;
    }
    else if (is_fuzzy_subsequence(query, query_len, target, target_len, &mask, &matched_chars)) {
        // Fuzzy subsequence: +10 (less than substring)
        score = 10;
    }
    else {
        // No match
        return result;
    }

    // Per-character bonus for longer matches
    score += (int)matched_chars * 2;

    result.score = score;
    result.match_mask = mask;
    result.matched = true;

    return result;
}

// ============================================================================
// UTF-8 Variant
// ============================================================================

FuzzyMatchResult fuzzy_match_utf8(const char* query, const char* target) {
    // Convert to wide strings and use the main function
    wchar_t query_wide[256];
    wchar_t target_wide[Git::MAX_PATH_LEN];

    if (!utf8_to_wide(query, query_wide, 256)) {
        return { 0, 0, false };
    }

    if (!utf8_to_wide(target, target_wide, Git::MAX_PATH_LEN)) {
        return { 0, 0, false };
    }

    return fuzzy_match(query_wide, target_wide);
}
